import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom'; // Importamos el navegador
import { loginUsuario } from '../services/authService';

const Login = () => {
    const navigate = useNavigate(); // Inicializamos la función para saltar de página
    const [form, setForm] = useState({ matricula: '', password: '' });
    const [cargando, setCargando] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        // 1. Limpieza de datos
        const matriculaLimpia = form.matricula.trim();
        const passwordLimpia = form.password.trim();

        if (!matriculaLimpia || !passwordLimpia) {
            alert("Por favor, llena ambos campos");
            return;
        }

        setCargando(true);
        console.log("Intentando login con:", { matricula: matriculaLimpia, password: passwordLimpia });

        try {
            const resultado = await loginUsuario(matriculaLimpia, passwordLimpia);
            
            // Convertimos a mayúsculas para asegurar la comparación
            if (resultado.trim().toUpperCase() === "BIENVENIDO_ADMIN") {
                alert("¡Acceso total concedido, riempy!");
                
                // Guardamos tu sesión localmente para que el sistema sepa quién eres
                localStorage.setItem('usuarioLogueado', matriculaLimpia);
                
                // ¡ESTA ES LA MAGIA! Nos manda a la ruta /inventario que definiste en App.js
                navigate("/inventario"); 
                
            } else {
                alert("Matrícula o contraseña incorrecta. Verifica la consola del Backend.");
            }
        } catch (error) {
            console.error("Error en el login:", error);
            alert("Error de conexión con el servidor");
        } finally {
            setCargando(false);
        }
    };

    return (
        <div style={{ textAlign: 'center', marginTop: '100px', fontFamily: 'Arial' }}>
            <h1 style={{ color: '#007bff' }}>Isla Tecnológica</h1>
            <p>Gestión de Inventario y Merchandise</p>
            
            <div style={{ 
                background: '#f4f4f4', 
                padding: '30px', 
                display: 'inline-block', 
                borderRadius: '15px',
                boxShadow: '0px 4px 10px rgba(0,0,0,0.1)' 
            }}>
                <form onSubmit={handleSubmit}>
                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ fontWeight: 'bold' }}>Matrícula:</label><br/>
                        <input 
                            type="text" 
                            value={form.matricula}
                            placeholder="Tu matrícula" 
                            onChange={(e) => setForm({...form, matricula: e.target.value})} 
                            style={{ padding: '10px', marginTop: '5px', width: '200px', borderRadius: '5px', border: '1px solid #ccc' }}
                        />
                    </div>
                    
                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ fontWeight: 'bold' }}>Contraseña:</label><br/>
                        <input 
                            type="password" 
                            value={form.password}
                            placeholder="********" 
                            onChange={(e) => setForm({...form, password: e.target.value})} 
                            style={{ padding: '10px', marginTop: '5px', width: '200px', borderRadius: '5px', border: '1px solid #ccc' }}
                        />
                    </div>
                    
                    <button 
                        type="submit" 
                        disabled={cargando}
                        style={{ 
                            padding: '12px 25px', 
                            cursor: cargando ? 'not-allowed' : 'pointer', 
                            backgroundColor: '#007bff', 
                            color: 'white', 
                            border: 'none', 
                            borderRadius: '5px',
                            fontWeight: 'bold',
                            width: '100%'
                        }}
                    >
                        {cargando ? "Verificando..." : "Entrar al Sistema"}
                    </button>
                </form>
            </div>
        </div>
    );
};

export default Login;
